import { merge } from 'lodash-es';

import {
  DEFAULT_MARKER_COLOR,
  DEFAULT_MARKER_HIDDEN,
  DEFAULT_MARKER_PRIORITY,
} from '../constants.js';
import {
  AnnotationsMarkerConfig,
  AnnotationsMarkerProps,
} from '../types/annotations-marker-props.js';
import { AnnotationsTrackProps } from '../types/annotations-track-props.js';

type MarkerOverridableProps = {
  color?: string;
};

/**
 * Overrides some markerProps with trackProps, when those particular markerProps are not present
 * @param markerProps -
 * @param trackProps -
 *
 * @returns overridden props
 */
const overrideMarkerProps = (
  markerProps: MarkerOverridableProps,
  trackProps: MarkerOverridableProps,
): MarkerOverridableProps => ({
  color: markerProps.color ?? trackProps.color,
});

/**
 * Populates missing marker props with defaults
 * Overrides missing marker props (color, symbol) with track props.
 * Marker props have higher priority than track's.
 *
 * @param marker - marker to override
 * @param trackProps - track props
 * @returns overridden marker
 */
export const populateMissingMarkerProps = (
  marker: AnnotationsMarkerProps,
  trackProps: AnnotationsTrackProps,
): AnnotationsMarkerConfig => {
  const defaults = {
    color: DEFAULT_MARKER_COLOR,
    priority: DEFAULT_MARKER_PRIORITY,
    hidden: DEFAULT_MARKER_HIDDEN,
    id: crypto.randomUUID(),
  };

  const mergedMarkerConfig = merge(
    {},
    defaults,
    marker,
    overrideMarkerProps(marker, trackProps),
  ) as AnnotationsMarkerConfig;

  // merge method from lodash changes the references making the dom ref to be different from received
  mergedMarkerConfig.symbol = marker.symbol ?? trackProps.symbol;

  return mergedMarkerConfig;
};
